          {/* 도서 정보 */}
          <div style={{ display: 'flex', gap: 12, marginBottom: 12, alignItems: 'flex-start' }}>
            <div style={{
              width: 58, height: 78, borderRadius: 7,
              background: 'var(--accent-green)',
