          <div style={{ display: 'flex', alignItems: 'center', gap: 8, marginBottom: 12 }}>
            <ProfileCircle name={ownerUserId} isMe={ownerUserId === currentUserId} size={24} />
            <span style={{ fontSize: 12, color: 'var(--text-primary)' }}>
              {ownerUserId === currentUserId ? `${currentUserId} (나)` : ownerUserId}
